"""matplotlib.text — text handling stubs."""


class Text:
    """Stub Text artist."""

    def __init__(self, x=0, y=0, text='', **kwargs):
        self._x = x
        self._y = y
        self._text = text
        self._fontsize = kwargs.get('fontsize', 12)
        self._color = kwargs.get('color', 'black')
        self._alpha = kwargs.get('alpha', None)

    def get_text(self): return self._text
    def set_text(self, t): self._text = t
    def get_fontsize(self): return self._fontsize
    def set_fontsize(self, s): self._fontsize = s
    def get_color(self): return self._color
    def set_color(self, c): self._color = c
    def set_visible(self, v): pass
    def set_position(self, xy): self._x, self._y = xy
    def get_position(self): return (self._x, self._y)
    def remove(self): pass


class Annotation(Text):
    """Stub Annotation artist."""

    def __init__(self, text, xy, xytext=None, xycoords='data',
                 textcoords=None, arrowprops=None, annotation_clip=None, **kwargs):
        super().__init__(xy[0], xy[1], text, **kwargs)
        self.xy = xy
        self.xytext = xytext
        self.xycoords = xycoords
        self.arrowprops = arrowprops
